// ── EMBEDDED STL DATA (5 parts: tumbler, lid, handle, boot, straw) ──
const BODY_B64   = "";
const CAP_B64    = "";
const HANDLE_B64 = "";
const BOOT_B64   = "";
const STRAP_B64  = "";

// ── COLOR PALETTES ──
var cfg=window.CUSTOMIZE_CONFIG||{};
const DEFAULT_BOTTLE=[{name:'Lavender',hex:'#c4b8e8'},{name:'Mermaid Green',hex:'#4aab6a'},{name:'Dragonfruit',hex:'#c4426a'},{name:'Pacific',hex:'#3b78c4'},{name:'Lava',hex:'#c94b2f'},{name:'Slate',hex:'#5e7080'},{name:'Tan',hex:'#c2a97d'},{name:'Carnation',hex:'#e8a29a'},{name:'Birch',hex:'#b8b0a0'},{name:'Black',hex:'#1a1a1a'},{name:'White',hex:'#f0f0ee'},{name:'Lupine',hex:'#5b4ea8'},{name:'Agave',hex:'#5aaa7a'}];
const DEFAULT_CAP=[{name:'Lavender',hex:'#c4b8e8'},{name:'Stone',hex:'#6b6b6b'},{name:'Black',hex:'#1a1a1a'},{name:'White',hex:'#f0f0ee'},{name:'Pacific',hex:'#3b78c4'},{name:'Neon Yellow',hex:'#ffe000'},{name:'Green',hex:'#3aaa5a'},{name:'Camellia',hex:'#e87aaa'}];
const DEFAULT_STRAP=[{name:'Lavender',hex:'#c4b8e8'},{name:'Stone',hex:'#6b6b6b'},{name:'Black',hex:'#1a1a1a'},{name:'Pacific',hex:'#3b78c4'},{name:'Camellia',hex:'#e87aaa'},{name:'Neon Yellow',hex:'#ffe000'}];
const bottleColors=cfg.bottle_colors&&cfg.bottle_colors.length?cfg.bottle_colors:DEFAULT_BOTTLE;
const capColors=cfg.cap_colors&&cfg.cap_colors.length?cfg.cap_colors:DEFAULT_CAP;
const strapColors=cfg.strap_colors&&cfg.strap_colors.length?cfg.strap_colors:DEFAULT_STRAP;
const DEFAULT_HANDLE=[{name:'Lavender',hex:'#c4b8e8'},{name:'Stone',hex:'#6b6b6b'},{name:'Pacific',hex:'#3b78c4'},{name:'Black',hex:'#1a1a1a'},{name:'White',hex:'#f0f0ee'},{name:'Neon Yellow',hex:'#ffe000'},{name:'Camellia',hex:'#e87aaa'},{name:'Mermaid Green',hex:'#4aab6a'}];
const handleColors=(cfg.handle_colors&&cfg.handle_colors.length)?cfg.handle_colors:((cfg.boot_colors&&cfg.boot_colors.length)?cfg.boot_colors:DEFAULT_HANDLE);
const bootColors=(cfg.boot_colors&&cfg.boot_colors.length)?cfg.boot_colors:((cfg.handle_colors&&cfg.handle_colors.length)?cfg.handle_colors:DEFAULT_HANDLE);
const sizes=cfg.sizes&&cfg.sizes.length?cfg.sizes:[{name:'40 oz',price:cfg.base_price||45}];
let basePrice=typeof cfg.base_price==='number'?cfg.base_price:45;
if(sizes.length>0){ var last=sizes[sizes.length-1]; basePrice=typeof last.price==='number'?last.price:basePrice; }
const productName=cfg.product_name||'Customize';
const currency=cfg.currency||'₹';
const engrEnabled=!!cfg.has_engraving;
var _ep=parseFloat(cfg.engraving_price);
const engrPrice=(engrEnabled&&isFinite(_ep))?Math.round(Math.max(0,_ep)*100)/100:0;
var _em=parseInt(cfg.engraving_max_chars,10);
const engrMax=(!isFinite(_em)||_em<1)?40:Math.min(500,_em);
function normEngraveType(t){
  var s=String(t==null?'':t).toLowerCase().trim();
  return (s==='text'||s==='upload'||s==='simple')?s:'simple';
}
const engrCatMode=!!cfg.engraving_category_mode;
const engrCats=(Array.isArray(cfg.engraving_categories)?cfg.engraving_categories:[]).map(function(c){
  if(!c||typeof c!=='object') return null;
  var o={};
  for(var k in c){ if(Object.prototype.hasOwnProperty.call(c,k)) o[k]=c[k]; }
  o.type=normEngraveType(o.type);
  return o;
}).filter(function(c){ return c!==null; });
const maxStep=typeof cfg.customize_max_step==='number'?cfg.customize_max_step:5;

const S={step:1,bIdx:0,cIdx:0,sIdx:0,hIdx:0,boIdx:0,sizeIdx:0,bOff:0,cOff:0,sOff:0,hOff:0,boOff:0,wish:false,qty:1,maxVisited:1,engrMode:'single',engrSlot:'top',engrSlots:{top:null,bottom:null}};
const VIS=7;

function normalizeHex(h){
  if(h==null||h==='') return '#888888';
  var s=String(h).trim();
  if(s.charAt(0)!=='#') s='#'+s;
  if(s.length===4){
    var r=s.charAt(1),g=s.charAt(2),b=s.charAt(3);
    s='#'+r+r+g+g+b+b;
  }
  return s;
}
function logoEngraveColorFromBodyHex(hex){
  var b=new THREE.Color(normalizeHex(hex));
  var lum=0.299*b.r+0.587*b.g+0.114*b.b;
  if(lum<=0.42){
    return new THREE.Color('#ececf2');
  }
  return new THREE.Color('#141418');
}

// Perch 1200ml CAD space → Three.js (same as perch-customizer.html; parts stay aligned)
const CX=48.5, CY=48.5, CZ=175.15, SCALE=230/350;
const ENGR_PLANE_W=42, ENGR_PLANE_H=20, ENGR_PREVIEW_ORDER=18;

// ── THREE.JS ──
let scene,camera,renderer,flipGroup,group;
const M={body:null,logo:null,cap:null,ring:null,handle:null,boot:null,straw:null};
var engrSlotMeshes={top:null,bottom:null};
let autoRot=true, mDown=false, mX=0, mY=0;

function initThree(){
  const wrap = document.getElementById('three-wrap');
  if(!wrap) return;
  if(scene){
    loadAllParts().catch(function(){});
    return;
  }

  const W = wrap.clientWidth || 500;
  const H = Math.max(wrap.clientHeight, 380);

  scene = new THREE.Scene();
  scene.background = new THREE.Color(0xf0f0ee);

  camera = new THREE.PerspectiveCamera(36, W/H, 0.1, 3000);
  camera.position.set(0, 0, 390);
  camera.lookAt(0, 0, 0);

  renderer = new THREE.WebGLRenderer({antialias:true, alpha:false, preserveDrawingBuffer:true});
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.setSize(W, H);
  renderer.shadowMap.enabled = false;
  if(THREE.sRGBEncoding!==undefined){
    renderer.outputEncoding=THREE.sRGBEncoding;
  }

  wrap.appendChild(renderer.domElement);

  scene.add(new THREE.AmbientLight(0xffffff, 0.68));
  const d1 = new THREE.DirectionalLight(0xffffff, 0.55);
  d1.position.set(140, 260, 220);
  scene.add(d1);
  const d2 = new THREE.DirectionalLight(0xffffff, 0.32);
  d2.position.set(-160, 90, -100); scene.add(d2);
  const d3 = new THREE.DirectionalLight(0xffffff, 0.18);
  d3.position.set(40, -120, 80); scene.add(d3);
  scene.add(new THREE.HemisphereLight(0xffffff, 0xeee8e4, 0.45));

  flipGroup = new THREE.Group();
  flipGroup.rotation.x = Math.PI;
  scene.add(flipGroup);

  group = new THREE.Group();
  group.rotation.y = 0.55;
  flipGroup.add(group);

  const c = renderer.domElement;
  c.addEventListener('mousedown', e=>{mDown=true;mX=e.clientX;mY=e.clientY;autoRot=false;});
  c.addEventListener('mousemove', e=>{
    if(!mDown) return;
    group.rotation.y += (e.clientX-mX)*0.013;
    group.rotation.x += (e.clientY-mY)*0.008;
    group.rotation.x = Math.max(-1.2, Math.min(1.2, group.rotation.x));
    mX=e.clientX; mY=e.clientY;
  });
  c.addEventListener('mouseup', ()=>mDown=false);
  c.addEventListener('mouseleave', ()=>mDown=false);

  let tx=0,ty=0;
  c.addEventListener('touchstart', e=>{tx=e.touches[0].clientX;ty=e.touches[0].clientY;autoRot=false;},{passive:true});
  c.addEventListener('touchmove', e=>{
    e.preventDefault();
    group.rotation.y += (e.touches[0].clientX-tx)*0.013;
    group.rotation.x += (e.touches[0].clientY-ty)*0.008;
    group.rotation.x = Math.max(-1.2, Math.min(1.2, group.rotation.x));
    tx=e.touches[0].clientX; ty=e.touches[0].clientY;
  },{passive:false});

  c.addEventListener('wheel', e=>{
    e.preventDefault();
    camera.position.z = Math.max(80, Math.min(700, camera.position.z + e.deltaY*0.5));
  },{passive:false});

  window.addEventListener('resize', ()=>{
    const W2=wrap.clientWidth, H2=Math.max(wrap.clientHeight,380);
    camera.aspect=W2/H2; camera.updateProjectionMatrix();
    renderer.setSize(W2,H2);
  });

  loadAllParts().catch(function(){});
  animLoop();
}

function b64ToArrayBuffer(b64){
  const bin=atob(b64), buf=new ArrayBuffer(bin.length), view=new Uint8Array(buf);
  for(let i=0;i<bin.length;i++) view[i]=bin.charCodeAt(i);
  return buf;
}

function parseBinaryStl(buf){
  const dv=new DataView(buf);
  const n=dv.getUint32(80,true);
  const verts=new Float32Array(n*9);
  let off=84;
  for(let i=0;i<n;i++){
    off+=12;
    for(let v=0;v<3;v++){
      const vi=i*9+v*3;
      const sx=dv.getFloat32(off,true);
      const sy=dv.getFloat32(off+4,true);
      const sz=dv.getFloat32(off+8,true);
      off+=12;
      verts[vi]  =(sx-CX)*SCALE;
      verts[vi+1]=(sz-CZ)*SCALE;
      verts[vi+2]=-(sy-CY)*SCALE;
    }
    off+=2;
  }
  const geo=new THREE.BufferGeometry();
  geo.setAttribute('position',new THREE.BufferAttribute(verts,3));
  geo.computeVertexNormals();
  return geo;
}
function parseAsciiStl(text){
  const verts=[];
  const re=/vertex\s+([-+eE\d.]+)\s+([-+eE\d.]+)\s+([-+eE\d.]+)/g;
  let m;
  while((m=re.exec(text))!==null){
    const sx=parseFloat(m[1]), sy=parseFloat(m[2]), sz=parseFloat(m[3]);
    verts.push((sx-CX)*SCALE,(sz-CZ)*SCALE,-(sy-CY)*SCALE);
  }
  if(verts.length<9) return null;
  const geo=new THREE.BufferGeometry();
  geo.setAttribute('position',new THREE.BufferAttribute(new Float32Array(verts),3));
  geo.computeVertexNormals();
  return geo;
}
function parseSTLMesh(buf){
  if(buf.byteLength>=84){
    const dv=new DataView(buf);
    const tri=dv.getUint32(80,true);
    if(tri>0&&tri<5e7&&84+tri*50===buf.byteLength){
      return parseBinaryStl(buf);
    }
  }
  const hdrLen=Math.min(120,buf.byteLength);
  const hdr=new TextDecoder('ascii').decode(new Uint8Array(buf,0,hdrLen));
  if(/^\s*solid\b/i.test(hdr)){
    const ascii=parseAsciiStl(new TextDecoder('utf-8').decode(buf));
    if(ascii) return ascii;
  }
  return parseBinaryStl(buf);
}

/** Some toolcut ring slices are paper-thin in one axis; after parse a +Z camera can see them edge-on. Rotate about centroid so the band faces the viewer. Skip full-size caps (restored cover.stl). */
function needsToolcutLidOrientation(geo){
  geo.computeBoundingBox();
  var b=geo.boundingBox;
  var ex=b.max.x-b.min.x, ey=b.max.y-b.min.y, ez=b.max.z-b.min.z;
  var mx=Math.max(ex,ey,ez);
  var mn=Math.min(ex,ey,ez);
  if(mx<1e-5) return false;
  return mn/mx<0.08&&mx<42;
}
function orientToolcutLidGeometry(geo){
  geo.computeBoundingBox();
  var b=geo.boundingBox;
  var cx=(b.min.x+b.max.x)*0.5;
  var cy=(b.min.y+b.max.y)*0.5;
  var cz=(b.min.z+b.max.z)*0.5;
  geo.translate(-cx,-cy,-cz);
  geo.rotateX(Math.PI/2);
  geo.translate(cx,cy,cz);
  geo.computeVertexNormals();
}

function makePartMaterial(key, hex){
  const h=normalizeHex(hex);
  if(key==='logo'){
    const c=logoEngraveColorFromBodyHex(h);
    const mat=new THREE.MeshStandardMaterial({
      color:c,
      metalness:0.22,
      roughness:0.42,
      envMapIntensity:0.95,
      side:THREE.DoubleSide,
    });
    mat.polygonOffset=true;
    mat.polygonOffsetFactor=-4;
    mat.polygonOffsetUnits=-2;
    mat._cur=c.clone();
    mat._tgt=c.clone();
    return mat;
  }
  const thin=key==='handle'||key==='boot'||key==='straw'||key==='cap'||key==='ring';
  const mat=new THREE.MeshStandardMaterial({
    color:new THREE.Color(h),
    metalness:0.04,
    roughness:0.38,
    envMapIntensity:0.85,
    side: thin ? THREE.DoubleSide : THREE.FrontSide,
  });
  if(thin){
    mat.polygonOffset=true;
    mat.polygonOffsetFactor=key==='straw'?-1.5:((key==='cap'||key==='ring')?2:(key==='boot'?2:1));
    mat.polygonOffsetUnits=key==='straw'?-1:1;
  }
  mat._cur=new THREE.Color(h);
  mat._tgt=new THREE.Color(h);
  return mat;
}

function disposeModelParts(){
  if(!group) return;
  while(group.children.length){
    var ch=group.children[0];
    group.remove(ch);
    if(ch.geometry) ch.geometry.dispose();
    if(ch.material){
      if(ch.material.map) ch.material.map.dispose();
      ch.material.dispose();
    }
  }
  M.body=M.logo=M.cap=M.ring=M.handle=M.boot=M.straw=null;
  engrSlotMeshes.top=engrSlotMeshes.bottom=null;
}

function partStlUrlsReady(){
  var u=cfg.part_stl_urls;
  return !!(u&&u.body&&u.cap&&u.ring&&u.straw&&u.handle&&u.boot);
}
function fetchStlBuffer(url){
  return fetch(url,{credentials:'same-origin'}).then(function(r){
    if(!r.ok) throw new Error('STL '+r.status+': '+url);
    return r.arrayBuffer();
  });
}
function loadAllParts(){
  var loadingEl=document.getElementById('loading-msg');
  function loadErr(msg){
    console.error(msg);
    if(loadingEl) loadingEl.innerHTML='<div style="color:#e04;font-size:13px;padding:20px;text-align:center;">'+String(msg)+'</div>';
  }
  function addPartMeshes(geos, lidOrientFix){
    if(lidOrientFix){
      if(geos.cap&&needsToolcutLidOrientation(geos.cap)) orientToolcutLidGeometry(geos.cap);
      if(geos.ring&&needsToolcutLidOrientation(geos.ring)) orientToolcutLidGeometry(geos.ring);
      if(geos.logo&&needsToolcutLidOrientation(geos.logo)) orientToolcutLidGeometry(geos.logo);
    }
    var hb=bottleColors[S.bIdx].hex, hc=capColors[S.cIdx].hex, hs=strapColors[S.sIdx].hex, hh=handleColors[S.hIdx].hex, hbo=bootColors[S.boIdx].hex;
    var hexMap={body:hb,cap:hc,ring:hc,handle:hh,boot:hbo,straw:hs};
    var drawOrder={body:0,logo:1.2,boot:1,handle:2,ring:2.6,cap:3,straw:15};
    var keys=['body','logo','ring','cap','handle','boot','straw'];
    for(var i=0;i<keys.length;i++){
      var key=keys[i];
      var geo=geos[key];
      if(!geo) continue;
      var mat=key==='logo'?makePartMaterial('logo', hb):makePartMaterial(key, hexMap[key]);
      var mesh=new THREE.Mesh(geo, mat);
      mesh.castShadow=false;
      mesh.receiveShadow=false;
      mesh.renderOrder=drawOrder[key]!==undefined?drawOrder[key]:0;
      if(key==='logo') mesh.position.z+=0.45;
      group.add(mesh);
      M[key]=mesh;
    }
    if(loadingEl) loadingEl.style.display='none';
    syncAllPartsFromState();
    syncEngraving3dPreview();
  }
  try{
    disposeModelParts();
    var hb=bottleColors[S.bIdx].hex, hc=capColors[S.cIdx].hex, hs=strapColors[S.sIdx].hex, hh=handleColors[S.hIdx].hex, hbo=bootColors[S.boIdx].hex;
    if(partStlUrlsReady()){
      var u=cfg.part_stl_urls;
      var logoUrl=u.logo&&String(u.logo).trim()?String(u.logo).trim():'';
      var logoP=logoUrl?fetchStlBuffer(logoUrl).catch(function(err){ console.warn('Logo STL skipped:', err&&err.message?err.message:err); return null; }):Promise.resolve(null);
      return Promise.all([
        fetchStlBuffer(u.body),
        fetchStlBuffer(u.cap),
        fetchStlBuffer(u.ring),
        fetchStlBuffer(u.handle),
        fetchStlBuffer(u.boot),
        fetchStlBuffer(u.straw),
        logoP
      ]).then(function(bufs){
        var geos={
          body: parseSTLMesh(bufs[0]),
          cap: parseSTLMesh(bufs[1]),
          ring: parseSTLMesh(bufs[2]),
          handle: parseSTLMesh(bufs[3]),
          boot: parseSTLMesh(bufs[4]),
          straw: parseSTLMesh(bufs[5])
        };
        if(bufs[6]&&bufs[6].byteLength) geos.logo=parseSTLMesh(bufs[6]);
        addPartMeshes(geos,true);
      }).catch(function(e){
        console.warn('Part STL fetch failed, using embedded meshes:', e);
        try{
          addPartMeshes({
            body: parseSTLMesh(b64ToArrayBuffer(BODY_B64)),
            cap: parseSTLMesh(b64ToArrayBuffer(BOOT_B64)),
            handle: parseSTLMesh(b64ToArrayBuffer(HANDLE_B64)),
            boot: parseSTLMesh(b64ToArrayBuffer(CAP_B64)),
            straw: parseSTLMesh(b64ToArrayBuffer(STRAP_B64))
          });
        }catch(err2){
          loadErr('Error: '+(err2&&err2.message?err2.message:String(err2)));
        }
      });
    }
    var parts=[
      ['body',BODY_B64,hb],
      ['cap',BOOT_B64,hc],
      ['handle',HANDLE_B64,hh],
      ['boot',CAP_B64,hbo],
      ['straw',STRAP_B64,hs],
    ];
    var drawOrder={body:0,logo:1.2,boot:1,handle:2,cap:3,straw:15};
    for(var i=0;i<parts.length;i++){
      var key=parts[i][0], b64=parts[i][1], hex=parts[i][2];
      var geo=parseSTLMesh(b64ToArrayBuffer(b64));
      var mat=makePartMaterial(key, hex);
      var mesh=new THREE.Mesh(geo, mat);
      mesh.castShadow=false;
      mesh.receiveShadow=false;
      mesh.renderOrder=drawOrder[key]!==undefined?drawOrder[key]:0;
      group.add(mesh);
      M[key]=mesh;
    }
    M.logo=null;
    if(loadingEl) loadingEl.style.display='none';
    syncAllPartsFromState();
    syncEngraving3dPreview();
    return Promise.resolve();
  }catch(e){
    console.error(e);
    loadErr('Error: '+e.message);
    return Promise.reject(e);
  }
}

function syncAllPartsFromState(){
  if(!M.body) return;
  var bh=bottleColors[S.bIdx]&&bottleColors[S.bIdx].hex;
  var ch=capColors[S.cIdx]&&capColors[S.cIdx].hex;
  var sh=strapColors[S.sIdx]&&strapColors[S.sIdx].hex;
  var hh=handleColors[S.hIdx]&&handleColors[S.hIdx].hex;
  var boh=bootColors[S.boIdx]&&bootColors[S.boIdx].hex;
  if(bh) snapMatColor(M.body, bh);
  if(M.logo&&M.logo.material&&bh){
    var lc=logoEngraveColorFromBodyHex(bh);
    M.logo.material._tgt.copy(lc);
    M.logo.material._cur.copy(lc);
    M.logo.material.color.copy(lc);
    M.logo.material.needsUpdate=true;
  }
  if(ch){ snapMatColor(M.cap, ch); if(M.ring) snapMatColor(M.ring, ch); }
  if(sh) snapMatColor(M.straw, sh);
  if(hh) snapMatColor(M.handle, hh);
  if(boh) snapMatColor(M.boot, boh);
}

function animLoop(){
  requestAnimationFrame(animLoop);
  if(autoRot) group.rotation.y += 0.005;
  ['body','logo','cap','ring','straw','handle','boot'].forEach(function(k){
    const mesh=M[k];
    if(!mesh||!mesh.material._cur) return;
    mesh.material._cur.lerp(mesh.material._tgt, 0.1);
    mesh.material.color.copy(mesh.material._cur);
  });
  renderer.render(scene,camera);
}

function snapMatColor(mesh, hex){
  if(!mesh||!mesh.material) return;
  var h=normalizeHex(hex);
  try{
    mesh.material._tgt.setStyle(h);
    mesh.material._cur.setStyle(h);
    mesh.material.color.setStyle(h);
  }catch(err){
    mesh.material._tgt.set(h);
    mesh.material._cur.set(h);
    mesh.material.color.set(h);
  }
  mesh.material.needsUpdate=true;
}
function setBodyColor(hex){ snapMatColor(M.body, hex); }
function setCapColor(hex){ snapMatColor(M.cap, hex); if(M.ring) snapMatColor(M.ring, hex); }
function setStrapColor(hex){
  snapMatColor(M.straw, normalizeHex(hex));
}
function setHandleColor(hex){ snapMatColor(M.handle, hex); }
function setBootColor(hex){ snapMatColor(M.boot, hex); }

function resetCam(){
  if(flipGroup) flipGroup.rotation.x=Math.PI;
  group.rotation.set(0,0.55,0);
  camera.position.set(0,0,390);
  autoRot=true;
}
function zoomIn()  { camera.position.z=Math.max(80,  camera.position.z-35); }
function zoomOut() { camera.position.z=Math.min(700, camera.position.z+35); }
function toggleWish(){
  S.wish=!S.wish;
  const b=document.getElementById('wish-btn');
  b.textContent=S.wish?'♥':'♡'; b.classList.toggle('active',S.wish);
}

// ── SWATCHES ──
function renderSw(id, colors_arr, sel, off, lblId){
  const w=document.getElementById(id); if(!w)return; w.innerHTML='';
  colors_arr.slice(off, off+VIS).forEach((c,i)=>{
    const ri=off+i, el=document.createElement('div');
    const hx=normalizeHex(c.hex||c.color||'#888888');
    el.className='swatch'+(ri===sel?' selected':'')+(c.outOfStock?' out-of-stock':'');
    el.style.background=hx; el.title=c.name;
    if(!c.outOfStock)el.onclick=()=>{
      var lbl=document.getElementById(lblId);
      if(id==='bottle-swatches'){ S.bIdx=ri; if(lbl) lbl.textContent=c.name; setBodyColor(hx); }
      else if(id==='cap-swatches'){ S.cIdx=ri; if(lbl) lbl.textContent=c.name; setCapColor(hx); }
      else if(id==='strap-swatches'){ S.sIdx=ri; if(lbl) lbl.textContent=c.name; setStrapColor(hx); }
      else if(id==='handle-swatches'){ S.hIdx=ri; if(lbl) lbl.textContent=c.name; setHandleColor(hx); }
      else if(id==='boot-swatches'){ S.boIdx=ri; if(lbl) lbl.textContent=c.name; setBootColor(hx); }
      renderAll();
    };
    w.appendChild(el);
  });
}
function shiftS(t,d){
  if(t==='bottle'){ S.bOff=Math.max(0,Math.min(bottleColors.length-VIS,S.bOff+d)); }
  else if(t==='cap'){ S.cOff=Math.max(0,Math.min(capColors.length-VIS,S.cOff+d)); }
  else if(t==='strap'){ S.sOff=Math.max(0,Math.min(strapColors.length-VIS,S.sOff+d)); }
  else if(t==='handle'){ S.hOff=Math.max(0,Math.min(handleColors.length-VIS,S.hOff+d)); }
  else if(t==='boot'){ S.boOff=Math.max(0,Math.min(bootColors.length-VIS,S.boOff+d)); }
  renderAll();
}
function renderAll(){
  renderSw('bottle-swatches',bottleColors,S.bIdx,S.bOff,'bottle-color-label');
  renderSw('cap-swatches',capColors,S.cIdx,S.cOff,'cap-color-label');
  renderSw('strap-swatches',strapColors,S.sIdx,S.sOff,'strap-color-label');
  renderSw('handle-swatches',handleColors,S.hIdx,S.hOff,'handle-color-label');
  renderSw('boot-swatches',bootColors,S.boIdx,S.boOff,'boot-color-label');
  syncAllPartsFromState();
  updatePrice();
}
function selectSize(idx){
  S.sizeIdx=idx;
  document.querySelectorAll('.size-card').forEach((c,i)=>{ c.classList.toggle('selected',i===idx); });
  if(sizes[idx]&&typeof sizes[idx].price==='number'){ basePrice=sizes[idx].price; updatePrice(); }
  syncAllPartsFromState();
}

function fmtMoney(n){
  return currency+Number(n).toLocaleString('en-IN',{minimumFractionDigits:2,maximumFractionDigits:2});
}
function removeEngraveSlotPreview(slot){
  var m=engrSlotMeshes[slot];
  if(m&&group){
    group.remove(m);
    if(m.geometry) m.geometry.dispose();
    if(m.material){
      if(m.material.map) m.material.map.dispose();
      m.material.dispose();
    }
  }
  engrSlotMeshes[slot]=null;
}
function wrapEngraveCanvasText(ctx, text, cx, cy, maxWidth, baseFontSize){
  var words=String(text||'').split(/\s+/).filter(function(w){ return w.length; });
  var lines=[];
  var line='';
  ctx.font='700 '+baseFontSize+"px 'Inter',system-ui,sans-serif";
  for(var i=0;i<words.length;i++){
    var test=line?line+' '+words[i]:words[i];
    if(ctx.measureText(test).width>maxWidth&&line){
      lines.push(line);
      line=words[i];
    }else line=test;
  }
  if(line) lines.push(line);
  var lh=baseFontSize*1.18;
  var startY=cy-(lines.length-1)*lh/2;
  for(var j=0;j<lines.length;j++){
    ctx.fillText(lines[j], cx, startY+j*lh);
  }
}
function drawEngraveSimplePreview(ctx, w, h, sel, cat){
  ctx.fillStyle='rgba(255,255,255,0.16)';
  ctx.fillRect(0,0,w,h);
  ctx.fillStyle='#141414';
  ctx.textAlign='center';
  ctx.textBaseline='middle';
  ctx.font='600 22px system-ui,sans-serif';
  var nm=(cat&&cat.name)||sel.name||'Custom';
  ctx.fillText(nm, w/2, h/2-8);
  ctx.font='300 40px serif';
  ctx.fillText('\u2726', w/2, h/2+28);
  return true;
}
function drawEngraveTextPreview(ctx, w, h, sel, cat){
  ctx.fillStyle='rgba(255,255,255,0.14)';
  ctx.fillRect(0,0,w,h);
  var tx=String(sel.text||'').trim();
  ctx.textAlign='center';
  ctx.textBaseline='middle';
  if(tx){
    ctx.fillStyle='#141414';
    var size=Math.min(56, Math.floor(w/Math.max(8, tx.length*0.52)));
    size=Math.max(20, Math.min(size, 52));
    wrapEngraveCanvasText(ctx, tx, w/2, h/2, w-36, size);
  }else{
    ctx.strokeStyle='rgba(0,0,0,0.22)';
    ctx.setLineDash([8,6]);
    ctx.strokeRect(16,16,w-32,h-32);
    ctx.setLineDash([]);
    ctx.fillStyle='rgba(0,0,0,0.38)';
    ctx.font='600 21px system-ui,sans-serif';
    ctx.fillText('Type to preview', w/2, h/2-10);
    ctx.font='500 15px system-ui,sans-serif';
    ctx.fillStyle='rgba(0,0,0,0.28)';
    var nm=(cat&&cat.name)||sel.name||'';
    ctx.fillText(nm||'Text', w/2, h/2+16);
  }
  return true;
}
function drawEngraveUploadPlaceholder(ctx, w, h, sel, cat){
  ctx.fillStyle='rgba(255,255,255,0.12)';
  ctx.fillRect(0,0,w,h);
  ctx.strokeStyle='rgba(0,0,0,0.2)';
  ctx.setLineDash([6,5]);
  ctx.strokeRect(16,16,w-32,h-32);
  ctx.setLineDash([]);
  ctx.fillStyle='rgba(0,0,0,0.34)';
  ctx.textAlign='center';
  ctx.textBaseline='middle';
  ctx.font='600 20px system-ui,sans-serif';
  ctx.fillText('Upload image', w/2, h/2-6);
  ctx.font='500 14px system-ui,sans-serif';
  ctx.fillStyle='rgba(0,0,0,0.26)';
  var nm=(cat&&cat.name)||sel.name||'';
  if(nm) ctx.fillText(nm, w/2, h/2+18);
  return true;
}
function makeEngravePreviewMesh(canvas){
  var tex=new THREE.CanvasTexture(canvas);
  tex.flipY=false;
  tex.needsUpdate=true;
  var mat=new THREE.MeshBasicMaterial({
    map:tex,
    transparent:true,
    opacity:0.97,
    depthWrite:false,
    side:THREE.DoubleSide,
  });
  mat.polygonOffset=true;
  mat.polygonOffsetFactor=-4;
  mat.polygonOffsetUnits=-2;
  var geo=new THREE.PlaneGeometry(ENGR_PLANE_W, ENGR_PLANE_H);
  var mesh=new THREE.Mesh(geo,mat);
  mesh.renderOrder=ENGR_PREVIEW_ORDER;
  mesh.castShadow=false;
  mesh.receiveShadow=false;
  return mesh;
}
function placeEngravePreviewMesh(mesh, yLocal){
  mesh.position.set(0, yLocal, 54);
  mesh.rotation.set(0, Math.PI, 0);
}
function loadEngraveUploadToMesh(slot, dataUrl, yLocal){
  removeEngraveSlotPreview(slot);
  var canvas=document.createElement('canvas');
  canvas.width=512;
  canvas.height=256;
  var ctx=canvas.getContext('2d');
  ctx.fillStyle='rgba(255,255,255,0.1)';
  ctx.fillRect(0,0,512,256);
  var mesh=makeEngravePreviewMesh(canvas);
  placeEngravePreviewMesh(mesh, yLocal);
  group.add(mesh);
  engrSlotMeshes[slot]=mesh;
  var img=new Image();
  img.onload=function(){
    if(engrSlotMeshes[slot]!==mesh) return;
    ctx.fillStyle='rgba(255,255,255,0.08)';
    ctx.fillRect(0,0,512,256);
    var pad=14;
    var cw=512-pad*2, ch=256-pad*2;
    var scale=Math.min(cw/img.width, ch/img.height);
    var w=img.width*scale, h=img.height*scale;
    ctx.drawImage(img,(512-w)/2,(256-h)/2,w,h);
    if(mesh.material.map) mesh.material.map.dispose();
    var nt=new THREE.CanvasTexture(canvas);
    nt.flipY=false;
    mesh.material.map=nt;
    mesh.material.map.needsUpdate=true;
    mesh.material.needsUpdate=true;
  };
  img.onerror=function(){};
  img.src=dataUrl;
}
function engrCategoryIconUrl(cat){
  if(!cat||!cat.icon) return '';
  var u=String(cat.icon).trim();
  if(!u) return '';
  if(/^https?:\/\//i.test(u)||u.indexOf('data:image/')===0||u.charAt(0)==='/') return u;
  return '';
}
function loadEngraveIconToMesh(slot, iconUrl, yLocal, sel, cat){
  removeEngraveSlotPreview(slot);
  var canvas=document.createElement('canvas');
  canvas.width=512;
  canvas.height=256;
  var ctx=canvas.getContext('2d');
  drawEngraveSimplePreview(ctx,512,256,sel,cat);
  var mesh=makeEngravePreviewMesh(canvas);
  placeEngravePreviewMesh(mesh, yLocal);
  group.add(mesh);
  engrSlotMeshes[slot]=mesh;
  var img=new Image();
  img.crossOrigin='anonymous';
  img.onload=function(){
    if(engrSlotMeshes[slot]!==mesh) return;
    ctx.fillStyle='rgba(255,255,255,0.14)';
    ctx.fillRect(0,0,512,256);
    var pad=18;
    var cw=512-pad*2, ch=256-pad*2;
    var scale=Math.min(cw/Math.max(1,img.width), ch/Math.max(1,img.height));
    var w=img.width*scale, h=img.height*scale;
    ctx.drawImage(img,(512-w)/2,(256-h)/2,w,h);
    if(mesh.material.map) mesh.material.map.dispose();
    var nt=new THREE.CanvasTexture(canvas);
    nt.flipY=false;
    mesh.material.map=nt;
    mesh.material.map.needsUpdate=true;
    mesh.material.needsUpdate=true;
  };
  img.onerror=function(){};
  img.src=iconUrl;
}
function syncEngraveSlotPlane(slot, sel, yLocal){
  removeEngraveSlotPreview(slot);
  if(!sel||!sel.slug||!group||!M.body) return;
  var cat=engrCatBySlug(sel.slug);
  var tp=cat?normEngraveType(cat.type):normEngraveType(sel.type);
  var canvas=document.createElement('canvas');
  canvas.width=512;
  canvas.height=256;
  var ctx=canvas.getContext('2d');
  if(tp==='upload'&&sel.image_data&&String(sel.image_data).length>30){
    loadEngraveUploadToMesh(slot, sel.image_data, yLocal);
    return;
  }
  if(tp==='simple'){
    var iu=engrCategoryIconUrl(cat);
    if(iu){
      loadEngraveIconToMesh(slot, iu, yLocal, sel, cat);
      return;
    }
  }
  var ok=false;
  if(tp==='simple') ok=drawEngraveSimplePreview(ctx,512,256,sel,cat);
  else if(tp==='text') ok=drawEngraveTextPreview(ctx,512,256,sel,cat);
  else if(tp==='upload') ok=drawEngraveUploadPlaceholder(ctx,512,256,sel,cat);
  if(!ok) return;
  var mesh=makeEngravePreviewMesh(canvas);
  placeEngravePreviewMesh(mesh, yLocal);
  group.add(mesh);
  engrSlotMeshes[slot]=mesh;
}
function syncEngraveLegacyTextPlane(text){
  removeEngraveSlotPreview('top');
  if(!group||!M.body||!text) return;
  var canvas=document.createElement('canvas');
  canvas.width=512;
  canvas.height=256;
  var ctx=canvas.getContext('2d');
  drawEngraveTextPreview(ctx,512,256,{text:text,type:'text'},null);
  var mesh=makeEngravePreviewMesh(canvas);
  placeEngravePreviewMesh(mesh, -12);
  group.add(mesh);
  engrSlotMeshes.top=mesh;
}
function syncEngraving3dPreview(){
  if(typeof THREE==='undefined'||!group) return;
  if(!engrEnabled||!M.body){
    removeEngraveSlotPreview('top');
    removeEngraveSlotPreview('bottom');
    return;
  }
  if(engrCatMode){
    // flipGroup.rotation.x = π inverts vertical screen sense: smaller group Y sits higher on the tumbler
    syncEngraveSlotPlane('top', S.engrSlots&&S.engrSlots.top, -12);
    if(slotEnabled('bottom')) syncEngraveSlotPlane('bottom', S.engrSlots&&S.engrSlots.bottom, 18);
    else removeEngraveSlotPreview('bottom');
    return;
  }
  removeEngraveSlotPreview('bottom');
  var ch=document.getElementById('customize-engraving-check');
  var ta=document.getElementById('customize-engraving-text');
  var on=ch&&ch.checked, tx=ta?String(ta.value||'').trim():'';
  if(on&&tx) syncEngraveLegacyTextPlane(tx);
  else removeEngraveSlotPreview('top');
}
function engrCatBySlug(slug){
  if(!slug) return null;
  for(var i=0;i<engrCats.length;i++){
    if(engrCats[i].slug===slug) return engrCats[i];
  }
  return null;
}
function activeEngrSel(){
  var s=(S.engrSlot==='bottom')?'bottom':'top';
  return S.engrSlots&&S.engrSlots[s]?S.engrSlots[s]:null;
}
function setActiveEngrSel(sel){
  var s=(S.engrSlot==='bottom')?'bottom':'top';
  if(!S.engrSlots) S.engrSlots={top:null,bottom:null};
  S.engrSlots[s]=sel;
  updateEngravingSlotUi();
}
function slotEnabled(slot){
  if(slot==='bottom') return S.engrMode==='double';
  return true;
}
function updateEngravingSlotUi(){
  var topBtn=document.getElementById('engr-slot-top');
  var botBtn=document.getElementById('engr-slot-bottom');
  if(topBtn) topBtn.classList.toggle('active',S.engrSlot!=='bottom');
  if(botBtn) botBtn.classList.toggle('active',S.engrSlot==='bottom');
  if(botBtn){
    var en=slotEnabled('bottom');
    botBtn.disabled=!en;
    botBtn.style.opacity=en?'1':'0.55';
  }
  function labelFor(sel){
    if(!sel||!sel.slug) return '';
    var c=engrCatBySlug(sel.slug);
    var nm=String(sel.name|| (c?c.name:'') || '').trim();
    var tp=c?normEngraveType(c.type):normEngraveType(sel.type);
    if(tp==='text' && sel.text) return nm+' — "'+String(sel.text).trim()+'"';
    if(tp==='upload') return nm+' — uploaded';
    return nm;
  }
  var topSub=document.getElementById('engr-slot-top-sub');
  var botSub=document.getElementById('engr-slot-bottom-sub');
  var ts=labelFor(S.engrSlots.top);
  var bs=labelFor(S.engrSlots.bottom);
  if(topSub) topSub.textContent=ts?ts:'Choose option';
  if(botSub) botSub.textContent=slotEnabled('bottom')?(bs?bs:'Choose option'):'Double mode only';
  var sum=document.getElementById('engraving-slot-summary');
  if(sum){
    var lines=[];
    if(ts) lines.push('<strong>Top:</strong> '+escapeHtml(ts));
    if(slotEnabled('bottom')&&bs) lines.push('<strong>Bottom:</strong> '+escapeHtml(bs));
    sum.innerHTML=lines.join(' · ');
    sum.style.display=lines.length?'block':'none';
  }
  syncEngraving3dPreview();
}
function escapeHtml(s){
  return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
function validateEngravingSelection(){
  if(!engrCatMode||!engrEnabled) return null;
  var slots=['top'];
  if(slotEnabled('bottom')) slots.push('bottom');
  for(var i=0;i<slots.length;i++){
    var sel=S.engrSlots&&S.engrSlots[slots[i]]?S.engrSlots[slots[i]]:null;
    if(!sel||!sel.slug) continue;
    var c=engrCatBySlug(sel.slug);
    if(!c) return 'Invalid engraving selection.';
    if(normEngraveType(c.type)==='text'&&!String(sel.text||'').trim()) return 'Please save your engraving text for "'+(c.name||'this option')+'".';
    if(normEngraveType(c.type)==='upload'&&!(sel.image_data&&String(sel.image_data).length)) return 'Please upload an image for "'+(c.name||'this option')+'".';
  }
  return null;
}
function engravingUnitAdd(){
  if(!engrEnabled) return 0;
  if(engrCatMode){
    var sum=0;
    var slots=['top'];
    if(slotEnabled('bottom')) slots.push('bottom');
    for(var i=0;i<slots.length;i++){
      var sel=S.engrSlots&&S.engrSlots[slots[i]]?S.engrSlots[slots[i]]:null;
      if(!sel||!sel.slug) continue;
      var c=engrCatBySlug(sel.slug);
      if(!c) continue;
      var tpn=normEngraveType(c.type);
      if(tpn==='text'&&!String(sel.text||'').trim()) continue;
      if(tpn==='upload'&&!(sel.image_data&&String(sel.image_data).length)) continue;
      sum += Math.round(Math.max(0,Number(c.price)||0)*100)/100;
    }
    return Math.round(sum*100)/100;
  }
  var ch=document.getElementById('customize-engraving-check');
  var ta=document.getElementById('customize-engraving-text');
  if(!ch||!ta||!ch.checked||ta.disabled) return 0;
  var t=String(ta.value||'').trim();
  if(!t) return 0;
  return engrPrice;
}
function updatePrice(){
  if(sizes.length&&sizes[S.sizeIdx]&&typeof sizes[S.sizeIdx].price==='number'){
    basePrice=sizes[S.sizeIdx].price;
  }
  var qty=Math.max(1,S.qty||1);
  var extra=engravingUnitAdd();
  var unit=basePrice+extra;
  var total=unit*qty;
  var tb=document.getElementById('top-cart-btn');
  if(tb) tb.textContent='Add to Cart – '+fmtMoney(total);
  var fp=document.getElementById('final-price'); if(fp) fp.textContent=fmtMoney(total);
  var fp2=document.getElementById('final-price-engr'); if(fp2) fp2.textContent=fmtMoney(total);
  var hint=document.getElementById('price-hint');
  if(hint){
    var s=fmtMoney(basePrice)+' size';
    if(extra>0) s+=' + '+fmtMoney(extra)+' engraving';
    if(qty>1) s+=' · '+qty+'× '+fmtMoney(unit)+' = '+fmtMoney(total);
    hint.textContent=s;
  }
}

function showEngravingGridView(){
  var gv=document.getElementById('engraving-grid-view');
  var dv=document.getElementById('engraving-detail-view');
  if(gv) gv.style.display='';
  if(dv) dv.style.display='none';
}
function showEngravingDetailView(){
  var gv=document.getElementById('engraving-grid-view');
  var dv=document.getElementById('engraving-detail-view');
  if(gv) gv.style.display='none';
  if(dv) dv.style.display='';
}
function renderEngravingGrid(){
  var g=document.getElementById('engraving-card-grid');
  if(!g) return;
  g.innerHTML='';
  engrCats.forEach(function(cat){
    var btn=document.createElement('button');
    btn.type='button';
    var sel=activeEngrSel();
    btn.className='engraving-card'+(sel&&sel.slug===cat.slug?' selected':'');
    var th=document.createElement('div');
    th.className='engraving-card-thumb';
    if(cat.icon){
      var im=document.createElement('img');
      im.src=cat.icon;
      im.alt='';
      im.referrerPolicy='no-referrer';
      th.appendChild(im);
    }else{
      var tp=normEngraveType(cat.type);
      var ph=document.createElement('div');
      ph.className='engraving-thumb-placeholder';
      if(tp==='upload'){
        ph.classList.add('is-graphic');
        ph.innerHTML='<span>YOUR</span><span>GRAPHIC</span><span>HERE</span>';
      }else if(tp==='text'){
        ph.classList.add('is-text');
        ph.innerHTML='<span>YOUR</span><span>TEXT</span><span>HERE</span>';
      }else{
        ph.classList.add('is-simple');
        ph.innerHTML='<span>\u2726</span>';
      }
      th.appendChild(ph);
    }
    var bd=document.createElement('div');
    bd.className='engraving-card-body';
    var t=document.createElement('div');
    t.className='engraving-card-title';
    t.textContent=cat.name||'';
    var pr=document.createElement('div');
    pr.className='engraving-card-price';
    pr.textContent=currency+Number(cat.price||0).toLocaleString('en-IN',{minimumFractionDigits:2,maximumFractionDigits:2});
    bd.appendChild(t); bd.appendChild(pr);
    var cv=document.createElement('span');
    cv.className='engraving-card-chev'; cv.textContent='›';
    btn.appendChild(th); btn.appendChild(bd); btn.appendChild(cv);
    btn.addEventListener('click',function(){ openEngravingCategory(cat); });
    g.appendChild(btn);
  });
}
function openEngravingCategory(cat){
  var tp=normEngraveType(cat.type);
  if(tp==='simple'){
    setActiveEngrSel({slug:cat.slug,name:cat.name,price:cat.price,type:tp});
    renderEngravingGrid();
    updatePrice();
    showEngravingGridView();
    return;
  }
  showEngravingDetailView();
  if(tp==='text'){
    var pre=activeEngrSel();
    setActiveEngrSel({slug:cat.slug,name:cat.name,price:cat.price,type:tp,text:(pre&&pre.slug===cat.slug)?String(pre.text||''):''});
  }else if(tp==='upload'){
    var preU=activeEngrSel();
    setActiveEngrSel({slug:cat.slug,name:cat.name,price:cat.price,type:tp,image_data:(preU&&preU.slug===cat.slug)?String(preU.image_data||''):''});
  }
  var title=document.getElementById('engraving-detail-title');
  var body=document.getElementById('engraving-detail-body');
  if(title) title.textContent=cat.name||'';
  if(!body) return;
  body.innerHTML='';
  if(tp==='text'){
    var ta=document.createElement('textarea');
    ta.className='engraving-textarea';
    ta.rows=3;
    ta.maxLength=engrMax;
    ta.placeholder='Enter text for engraving';
    var cur=activeEngrSel();
    ta.value=(cur&&cur.slug===cat.slug)?(cur.text||''):'';
    ta.addEventListener('input',function(){
      var s=(S.engrSlot==='bottom')?'bottom':'top';
      if(!S.engrSlots) S.engrSlots={top:null,bottom:null};
      var row=S.engrSlots[s];
      if(row&&row.slug===cat.slug){
        row.text=ta.value;
        syncEngraving3dPreview();
      }
    });
    var sub=document.createElement('button');
    sub.type='button'; sub.className='next-btn'; sub.style.marginTop='10px';
    sub.textContent='Save';
    sub.addEventListener('click',function(){
      var tx=String(ta.value||'').trim();
      if(!tx){ alert('Please enter engraving text.'); return; }
      setActiveEngrSel({slug:cat.slug,name:cat.name,price:cat.price,type:tp,text:tx});
      renderEngravingGrid();
      updatePrice();
      showEngravingGridView();
    });
    body.appendChild(ta); body.appendChild(sub);
  }else if(tp==='upload'){
    var uid='engr-upload-'+String(cat.slug||'x').replace(/[^a-z0-9\-]/gi,'');
    var lab=document.createElement('label');
    lab.className='engraving-upload-label';
    lab.setAttribute('for',uid);
    lab.textContent='Choose image file';
    var inp=document.createElement('input');
    inp.id=uid;
    inp.type='file';
    inp.className='engraving-file-input';
    inp.accept='image/jpeg,image/png,image/webp,.jpg,.jpeg,.png,.webp';
    inp.addEventListener('change',function(){
      var f=inp.files&&inp.files[0];
      if(!f) return;
      var r=new FileReader();
      r.onload=function(){
        var d=String(r.result||'');
        if(d.length>1400000||!/^data:image\//.test(d)) return;
        var s=(S.engrSlot==='bottom')?'bottom':'top';
        if(!S.engrSlots) S.engrSlots={top:null,bottom:null};
        var row=S.engrSlots[s];
        if(row&&row.slug===cat.slug){
          row.image_data=d;
          updatePrice();
          syncEngraving3dPreview();
        }
      };
      r.readAsDataURL(f);
    });
    var hint=document.createElement('p');
    hint.className='engraving-hint';
    hint.textContent='PNG, JPG, or WebP. Then tap “Use this image”.';
    var sub=document.createElement('button');
    sub.type='button'; sub.className='next-btn'; sub.style.marginTop='10px';
    sub.textContent='Use this image';
    sub.addEventListener('click',function(){
      var f=inp.files&&inp.files[0];
      if(!f){ alert('Choose an image file.'); return; }
      var r=new FileReader();
      r.onload=function(){
        var d=String(r.result||'');
        if(d.length>1400000){ alert('Image is too large.'); return; }
        if(!/^data:image\//.test(d)){ alert('Invalid image.'); return; }
        setActiveEngrSel({slug:cat.slug,name:cat.name,price:cat.price,type:tp,image_data:d});
        renderEngravingGrid();
        updatePrice();
        showEngravingGridView();
      };
      r.readAsDataURL(f);
    });
    body.appendChild(hint); body.appendChild(lab); body.appendChild(inp); body.appendChild(sub);
  }
}

function updateNavSteps(){
  document.querySelectorAll('.nav-step').forEach(function(n){
    var st=parseInt(n.getAttribute('data-step'),10);
    n.classList.toggle('active',st===S.step);
    n.classList.toggle('done',st<S.step);
  });
}

function goTo(s){
  if(s<1||s>maxStep) return;
  S.step=s;
  S.maxVisited=Math.max(S.maxVisited||1,s);
  document.querySelectorAll('.step-panel').forEach(function(p){ p.classList.remove('active'); });
  var p=document.getElementById('panel-'+s);
  if(p) p.classList.add('active');
  updateNavSteps();
  var rc=document.querySelector('.customize-page .right-col');
  if(rc) rc.scrollTop=0;
  if(engrCatMode&&s===6) showEngravingGridView();
  if(engrCatMode&&s===6) syncEngraving3dPreview();
  renderAll();
}

function shareCustomizeDesign(){
  var url=window.location.href;
  if(navigator.clipboard&&navigator.clipboard.writeText){
    navigator.clipboard.writeText(url).then(function(){
      alert('Page link copied. Paste it to share this customizer.');
    }).catch(function(){
      window.prompt('Copy this link:',url);
    });
  }else{
    window.prompt('Copy this link:',url);
  }
}

function startOverCustomize(){
  S.bIdx=S.cIdx=S.sIdx=S.hIdx=S.boIdx=0;
  S.bOff=S.cOff=S.sOff=S.hOff=S.boOff=0;
  S.qty=1;
  S.maxVisited=1;
  var q=document.getElementById('customize-qty');
  if(q) q.value='1';
  var staticSz=document.getElementById('size-static-only');
  if(staticSz){
    S.sizeIdx=parseInt(staticSz.getAttribute('data-size-idx')||'0',10);
  }else{
    var last=Math.max(0,sizes.length-1);
    S.sizeIdx=last;
    document.querySelectorAll('.size-card').forEach(function(c,i){ c.classList.toggle('selected',i===last); });
  }
  if(sizes[S.sizeIdx]&&typeof sizes[S.sizeIdx].price==='number') basePrice=sizes[S.sizeIdx].price;
  var ech=document.getElementById('customize-engraving-check');
  var eta=document.getElementById('customize-engraving-text');
  if(ech){ ech.checked=false; }
  if(eta){ eta.value=''; eta.disabled=true; }
  S.engrMode='single';
  S.engrSlot='top';
  S.engrSlots={top:null,bottom:null};
  if(engrCatMode){ renderEngravingGrid(); showEngravingGridView(); updateEngravingSlotUi(); }
  renderAll();
  updatePrice();
  goTo(1);
  if(typeof resetCam==='function') resetCam();
}

function syncCustomizeQtyMinOne(){
  var sel=document.getElementById('customize-qty');
  var raw=sel?parseInt(sel.value,10):S.qty;
  if(!isFinite(raw)||raw<1) raw=1;
  var maxOpt=1;
  if(sel){
    sel.querySelectorAll('option').forEach(function(o){
      var v=parseInt(o.value,10);
      if(isFinite(v)&&v>maxOpt) maxOpt=v;
    });
    raw=Math.min(Math.max(1,raw),maxOpt);
    sel.value=String(raw);
  }
  S.qty=raw;
  return raw;
}

function onCustomizeQtyChange(sel){
  if(!sel) return;
  var n=parseInt(sel.value,10);
  if(!isFinite(n)||n<1) n=1;
  var maxOpt=1;
  sel.querySelectorAll('option').forEach(function(o){
    var v=parseInt(o.value,10);
    if(isFinite(v)&&v>maxOpt) maxOpt=v;
  });
  n=Math.min(Math.max(1,n),maxOpt);
  sel.value=String(n);
  S.qty=n;
  updatePrice();
}

function captureCustomizePreviewDataUrl(){
  if(!renderer||!scene||!camera) return null;
  try{
    renderer.render(scene,camera);
    return renderer.domElement.toDataURL('image/png',0.92);
  }catch(e){
    console.warn(e);
    return null;
  }
}

function buildCustomizationPayload(){
  var sn=sizes[S.sizeIdx]?sizes[S.sizeIdx].name:'';
  var o={
    size_idx:S.sizeIdx,
    size_name:sn,
    product_title:productName,
    colors:{
      body:{name:bottleColors[S.bIdx].name,hex:bottleColors[S.bIdx].hex},
      lid_ring:{name:capColors[S.cIdx].name,hex:capColors[S.cIdx].hex},
      straw:{name:strapColors[S.sIdx].name,hex:strapColors[S.sIdx].hex},
      handle:{name:handleColors[S.hIdx].name,hex:handleColors[S.hIdx].hex},
      bottom_base:{name:bootColors[S.boIdx].name,hex:bootColors[S.boIdx].hex}
    }
  };
  if(engrCatMode){
    var top=S.engrSlots&&S.engrSlots.top?S.engrSlots.top:null;
    var bot=(S.engrMode==='double' && S.engrSlots&&S.engrSlots.bottom)?S.engrSlots.bottom:null;
    if((top&&top.slug)||(bot&&bot.slug)){
      o.engraving={ mode:(S.engrMode==='double'?'double':'single'), top:null, bottom:null };
      if(top&&top.slug){
        o.engraving.top={ category_slug:top.slug, category_name:String(top.name||'') };
        if(top.text) o.engraving.top.text=top.text;
        if(top.image_data) o.engraving.top.image_data=top.image_data;
      }
      if(bot&&bot.slug){
        o.engraving.bottom={ category_slug:bot.slug, category_name:String(bot.name||'') };
        if(bot.text) o.engraving.bottom.text=bot.text;
        if(bot.image_data) o.engraving.bottom.image_data=bot.image_data;
      }
    }
  }else if(engrEnabled){
    var ch=document.getElementById('customize-engraving-check');
    var ta=document.getElementById('customize-engraving-text');
    if(ch&&ch.checked&&ta&&!ta.disabled){
      var et=String(ta.value||'').trim();
      if(et) o.engraving_text=et;
    }
  }
  return o;
}

function buildCustomizeCartPayload(){
  var pid=typeof cfg.cart_product_id==='number'?cfg.cart_product_id:parseInt(String(cfg.cart_product_id||''),10);
  if(!pid) return null;
  if(sizes[S.sizeIdx]&&typeof sizes[S.sizeIdx].price==='number') basePrice=sizes[S.sizeIdx].price;
  var unit=basePrice+engravingUnitAdd();
  var qty=syncCustomizeQtyMinOne();
  var preview=captureCustomizePreviewDataUrl();
  var body={
    product_id:pid,
    quantity:qty,
    custom_unit_price:unit,
    customization:buildCustomizationPayload()
  };
  if(preview) body.customization_image=preview;
  return {body:body,unit:unit,qty:qty};
}

function addToCart(){
  var engrErr=validateEngravingSelection();
  if(engrErr){ alert(engrErr); return; }
  var meta=buildCustomizeCartPayload();
  if(!meta){
    alert('Cart product is not set. Ensure an active catalog product exists with slug 1200ml-running-tumbler (run seeders).');
    return;
  }
  updatePrice();
  var unit=meta.unit,qty=meta.qty,body=meta.body;

  var tb=document.getElementById('top-cart-btn');
  var ob=tb?tb.textContent:'';
  if(tb){ tb.disabled=true; tb.textContent='Adding…'; }

  var csrf=document.querySelector('meta[name="csrf-token"]');
  var token=csrf?csrf.getAttribute('content'):'';
  fetch('/api/cart/add',{
    method:'POST',
    headers:{
      'Content-Type':'application/json',
      'Accept':'application/json',
      'X-CSRF-TOKEN':token,
      'X-Requested-With':'XMLHttpRequest'
    },
    credentials:'same-origin',
    body:JSON.stringify(body)
  }).then(function(r){
    return r.json().then(function(d){ return {ok:r.ok,data:d}; });
  }).then(function(res){
    if(res.data&&res.data.success){
      if(typeof window.updateCartCount==='function') window.updateCartCount();
      if(typeof window.showNotification==='function'){
        window.showNotification('Added to cart','success');
      }else{
        alert('Added to cart.');
      }
    }else{
      var msg=(res.data&&res.data.message)?res.data.message:'Could not add to cart.';
      if(typeof window.showNotification==='function') window.showNotification(msg,'error');
      else alert(msg);
    }
  }).catch(function(){
    if(typeof window.showNotification==='function') window.showNotification('Network error','error');
    else alert('Network error. Please try again.');
  }).finally(function(){
    if(tb){ tb.disabled=false; tb.textContent=ob||('Add to Cart – '+fmtMoney(unit*qty)); }
    updatePrice();
  });
}

function buyItNow(){
  var engrErr=validateEngravingSelection();
  if(engrErr){ alert(engrErr); return; }
  var meta=buildCustomizeCartPayload();
  if(!meta){
    alert('Cart product is not set. Ensure an active catalog product exists with slug 1200ml-running-tumbler (run seeders).');
    return;
  }
  updatePrice();
  var checkoutUrl=(typeof window.CUSTOMIZE_CHECKOUT_URL==='string'&&window.CUSTOMIZE_CHECKOUT_URL)?window.CUSTOMIZE_CHECKOUT_URL:'/checkout';
  var unit=meta.unit,qty=meta.qty,body=meta.body;
  var btns=document.querySelectorAll('.customize-checkout-btn');
  var prev=[];
  btns.forEach(function(b){
    prev.push(b.textContent);
    b.disabled=true;
    b.textContent='Please wait…';
  });

  var csrf=document.querySelector('meta[name="csrf-token"]');
  var token=csrf?csrf.getAttribute('content'):'';
  fetch('/api/cart/add',{
    method:'POST',
    headers:{
      'Content-Type':'application/json',
      'Accept':'application/json',
      'X-CSRF-TOKEN':token,
      'X-Requested-With':'XMLHttpRequest'
    },
    credentials:'same-origin',
    body:JSON.stringify(body)
  }).then(function(r){
    return r.json().then(function(d){ return {ok:r.ok,data:d}; });
  }).then(function(res){
    if(res.data&&res.data.success){
      if(typeof window.updateCartCount==='function') window.updateCartCount();
      window.location.href=checkoutUrl;
      return;
    }
    var msg=(res.data&&res.data.message)?res.data.message:'Could not continue to checkout.';
    if(typeof window.showNotification==='function') window.showNotification(msg,'error');
    else alert(msg);
  }).catch(function(){
    if(typeof window.showNotification==='function') window.showNotification('Network error','error');
    else alert('Network error. Please try again.');
  }).finally(function(){
    btns.forEach(function(b,i){
      b.disabled=false;
      b.textContent=prev[i]||'Buy it now';
    });
    updatePrice();
  });
}

window.addEventListener('DOMContentLoaded',()=>{
  var bl=document.getElementById('bottle-color-label');if(bl)bl.textContent=bottleColors[S.bIdx].name;
  var cl=document.getElementById('cap-color-label');if(cl)cl.textContent=capColors[S.cIdx].name;
  var sl=document.getElementById('strap-color-label');if(sl)sl.textContent=strapColors[S.sIdx].name;
  var hdl=document.getElementById('handle-color-label');if(hdl)hdl.textContent=handleColors[S.hIdx].name;
  var bol=document.getElementById('boot-color-label');if(bol)bol.textContent=bootColors[S.boIdx].name;
  var sc=document.querySelectorAll('.size-card');
  var staticSz=document.getElementById('size-static-only');
  var selCard=document.querySelector('.size-card.selected');
  if(staticSz){ S.sizeIdx=parseInt(staticSz.getAttribute('data-size-idx')||'0',10); }
  else if(selCard){ S.sizeIdx=parseInt(selCard.getAttribute('data-size-idx')||'0',10); }
  else { S.sizeIdx=Math.max(0,sizes.length-1); sc.forEach((c,i)=>{ if(i===S.sizeIdx)c.classList.add('selected'); }); }
  if(sizes[S.sizeIdx]&&typeof sizes[S.sizeIdx].price==='number'){ basePrice=sizes[S.sizeIdx].price; }
  if(engrCatMode){
    renderEngravingGrid();
    var bk=document.getElementById('engraving-detail-back');
    if(bk) bk.addEventListener('click',showEngravingGridView);
    var r1=document.getElementById('engr-mode-single');
    var r2=document.getElementById('engr-mode-double');
    var topBtn=document.getElementById('engr-slot-top');
    var botBtn=document.getElementById('engr-slot-bottom');
    function setMode(m){
      S.engrMode=(m==='double')?'double':'single';
      if(S.engrMode!=='double'){ S.engrSlot='top'; }
      updateEngravingSlotUi();
      renderEngravingGrid();
      updatePrice();
    }
    function setSlot(s){
      if(s==='bottom' && !slotEnabled('bottom')) return;
      S.engrSlot=(s==='bottom')?'bottom':'top';
      updateEngravingSlotUi();
      renderEngravingGrid();
    }
    if(r1) r1.addEventListener('change',function(){ if(r1.checked) setMode('single'); });
    if(r2) r2.addEventListener('change',function(){ if(r2.checked) setMode('double'); });
    if(topBtn) topBtn.addEventListener('click',function(){ setSlot('top'); });
    if(botBtn) botBtn.addEventListener('click',function(){ setSlot('bottom'); });
    // init UI
    if(r1) r1.checked=true;
    updateEngravingSlotUi();
  }else if(engrEnabled){
    var ch=document.getElementById('customize-engraving-check');
    var ta=document.getElementById('customize-engraving-text');
    if(ch&&ta){
      if(ta.getAttribute('maxlength')){ var mx=parseInt(ta.getAttribute('maxlength'),10); if(isFinite(mx)&&mx>0) ta.setAttribute('maxlength',Math.min(500,mx)); }
      else { ta.setAttribute('maxlength',String(engrMax)); }
      function syncEngrUi(){ ta.disabled=!ch.checked; if(!ch.checked) ta.value=''; updatePrice(); syncEngraving3dPreview(); }
      ch.addEventListener('change',syncEngrUi);
      ta.addEventListener('input',function(){ updatePrice(); syncEngraving3dPreview(); });
      syncEngrUi();
    }
  }
  renderAll();
  updatePrice();
  initThree();
  updateNavSteps();
});
